/** Rosmarino color palette — CSS custom properties */
export interface ColorPaletteTokens {
  /** #6B2D3E — primary brand color */
  '--burgundy': string;
  '--burgundy-light': string;
  '--burgundy-dark': string;
  /** #A0673C — accent, most-used color */
  '--cognac': string;
  '--cognac-light': string;
  '--cognac-dark': string;
  /** #2E4A3A — nature/origin accent */
  '--forest': string;
  '--forest-light': string;
  '--forest-dark': string;
  /** #FDFBF7 — default page background */
  '--warm-white': string;
  /** #F5F0E8 — card/surface background */
  '--cream': string;
  /** #E8E0D4 — borders, dividers */
  '--cream-dark': string;
  /** #1A1A18 — primary text */
  '--charcoal': string;
  /** #8A8680 — secondary/muted text */
  '--stone': string;
  '--stone-light': string;
  '--blue-steel': string;
  '--terracotta': string;
  '--pink-blush': string;
}
